VSaveImage Example

VB Example:

Dim found as Boolean

m_spel.VRun("Seq")

m_spel.VGet("Seq", SpelVisionProps.AllFound, found)

If Not found Then

   m_spel.VSaveImage(seq01, "d:\reject.bmp")

End If

C# Example:

bool found;

m_spel.VRun("Seq");

m_spel.VGet("Seq", SpelVisionProps.AllFound, out found);

if (!found)

   m_spel.VSaveImage("Seq", @"d:\reject.mim");

